import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse('{"title":"How I run multiple $10K MRR companies on a $20/month tech stack","description":"","frontmatter":{"title":"How I run multiple $10K MRR companies on a $20/month tech stack","source":"https://stevehanov.ca/blog/how-i-run-multiple-10k-mrr-companies-on-a-20month-tech-stack","clipped_at":"2026-04-21","category":"[AI_IDE_And_CLI]","tags":["lean-startup","sqlite","vllm","go-lang"],"status":"raw","compiled":false},"headers":[],"relativePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How I run 10K MRR on 20 budget.md","filePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How I run 10K MRR on 20 budget.md","lastUpdated":null}'),s={name:"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How I run 10K MRR on 20 budget.md"};function r(i,e,l,p,u,c){return t(),n("div",null,[...e[0]||(e[0]=[o(`<p>Last night, I was rejected from yet another pitch night. It was just the pre-interview, and the problem wasn&#39;t my product. I already have MRR. I already have users who depend on it every day.</p><p>The feedback was simply: <em>&quot;What do you even need funding for?&quot;</em></p><p>I hear this time and time again when I try to grow my ideas. Running lean is in my DNA. I&#39;ve built tools you might have used, like <a href="https://websequencediagrams.com/" target="_blank" rel="noreferrer">websequencediagrams.com</a>, and niche products you probably haven&#39;t, like <a href="https://eh-trade.ca/" target="_blank" rel="noreferrer">eh-trade.ca</a>. That obsession with efficiency leads to successful bootstrapping, and honestly, a lot of VCs <em>hate</em> that.</p><p>Keeping costs near zero gives you the exact same runway as getting a million dollars in funding with a massive burn rate. It&#39;s less stressful, it keeps your architecture incredibly simple, and it gives you adequate time to find product-market fit without the pressure of a board breathing down your neck.</p><p>If you are tired of the modern &quot;Enterprise&quot; boilerplate, here is the exact playbook of how I build my companies to run on nearly nothing.</p><h2 id="use-a-lean-server" tabindex="-1">Use a lean server <a class="header-anchor" href="#use-a-lean-server" aria-label="Permalink to &quot;Use a lean server&quot;">​</a></h2><p>The naive way to launch a web app in 2026 is to fire up AWS, provision an EKS cluster, set up an RDS instance, configure a NAT Gateway, and accidentally spend $300 a month before a single user has even looked at your landing page.</p><p>The smart way is to rent a single Virtual Private Server (VPS).</p><p>First thing I do is get a cheap, reliable box. Forget AWS. You aren&#39;t going to need it, and their control panel is a labyrinth designed to extract billing upgrades. I use Linode or DigitalOcean. Pay no more than $5 to $10 a month.</p><p>1GB of RAM sounds terrifying to modern web developers, but it is plenty if you know what you are doing. If you need a little breathing room, just use a swapfile.</p><p><img src="https://stevehanov.ca/blog/images/95f16b3dbf861a9156cb2c6d1be39f5e2fcfc1b1f4c5f11ee6f9e182bd4c5f5a.png" alt="image.png"></p><p>The goal is to serve requests, not to maintain infrastructure. When you have one server, you know exactly where the logs are, exactly why it crashed, and exactly how to restart it.</p><h2 id="use-a-lean-language" tabindex="-1">Use a lean language <a class="header-anchor" href="#use-a-lean-language" aria-label="Permalink to &quot;Use a lean language&quot;">​</a></h2><p>Now you have constraints. You only have a gigabyte of memory. You <em>could</em> run Python or Ruby as your main backend language—but why would you? You&#39;ll spend half your RAM just booting the interpreter and managing <code>gunicorn</code> workers.</p><p>I write my backends in Go.</p><p>Go is infinitely more performant for web tasks, it&#39;s strictly typed, and—crucially for 2026—it is incredibly easy for LLMs to reason about. But the real magic of Go is the deployment process. There is no <code>pip install</code> dependency hell. There is no virtual environment. You compile your entire application into a single, statically linked binary on your laptop, <code>scp</code> it to your $5 server, and run it.</p><p>Here is what a complete, production-ready web server looks like in Go. No bloated frameworks required:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>package main</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import (</span></span>
<span class="line"><span>    &quot;fmt&quot;</span></span>
<span class="line"><span>    &quot;net/http&quot;</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func main() {</span></span>
<span class="line"><span>    http.HandleFunc(&quot;/&quot;, func(w http.ResponseWriter, r *http.Request) {</span></span>
<span class="line"><span>        fmt.Fprintf(w, &quot;Hello, your MRR is safe here.&quot;)</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // This will comfortably handle 10,000s of requests per second</span></span>
<span class="line"><span>    // on a potato.</span></span>
<span class="line"><span>    http.ListenAndServe(&quot;:8080&quot;, nil) </span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="use-local-ai-for-long-running-tasks" tabindex="-1">Use Local AI for long-running tasks <a class="header-anchor" href="#use-local-ai-for-long-running-tasks" aria-label="Permalink to &quot;Use Local AI for long-running tasks&quot;">​</a></h2><p>If you have a graphics card sitting somewhere in your house, you already have <em>unlimited</em> AI credits.</p><p>When I was building eh-trade.ca, I had a specific problem: I needed to perform deep, qualitative stock market research on thousands of companies, summarizing massive quarterly reports. The naive solution is to throw all of this at the OpenAI API. I could have paid hundreds of dollars in API credits, only to find a logic bug in my prompt loop that required me to run the whole batch over again.</p><p>Instead, I&#39;m running VLLM on a dusty $900 graphics card (an RTX 3090 with 24GB of VRAM) I bought off Facebook Marketplace. It’s an upfront investment, sure, but I never have to pay a toll to an AI provider for batch processing again.</p><p>For local AI, you have a distinct upgrade path:</p><ul><li><strong>Start with Ollama.</strong> It sets up in one command (<code>ollama run qwen3:32b</code>) and lets you try out dozens of models instantly. It&#39;s the perfect environment for iterating on prompts.</li><li><strong>Move to VLLM for production.</strong> Once you have a system that works, Ollama becomes a bottleneck for concurrent requests. VLLM locks your GPU to one model, but it is <em>drastically</em> faster because it uses PagedAttention. Structure your system so you send 8 or 16 async requests simultaneously. VLLM will batch them together in the GPU memory, and all 16 will finish in roughly the same time it takes to process one.</li><li><strong>Use Transformer Lab for anything more advanced.</strong> If you need to do any model pre-training or fine-tuning, <a href="https://lab.cloud/" target="_blank" rel="noreferrer">Transformer Lab</a> makes it easy on local hardware.</li></ul><p>To manage all this, I built <a href="https://github.com/smhanov/laconic" target="_blank" rel="noreferrer">laconic</a>, an agentic researcher specifically optimized for running in a constrained 8K context window. It manages the LLM context like an operating system&#39;s virtual memory manager—it &quot;pages out&quot; the irrelevant baggage of a conversation, keeping only the absolute most critical facts in the active LLM context window.</p><p>I also use <a href="https://github.com/smhanov/llmhub" target="_blank" rel="noreferrer">llmhub</a>, which abstracts any LLM into a simple provider/endpoint/apikey combo, gracefully handling both text and image IO whether the model is running under my desk or in the cloud.</p><h2 id="use-openrouter-for-your-fast-smart-llm" tabindex="-1">Use OpenRouter for your Fast/Smart LLM <a class="header-anchor" href="#use-openrouter-for-your-fast-smart-llm" aria-label="Permalink to &quot;Use OpenRouter for your Fast/Smart LLM&quot;">​</a></h2><p>You can&#39;t do <em>everything</em> locally. Sometimes you need the absolute cutting-edge reasoning of Claude 3.5 Sonnet or GPT-4o for user-facing, low-latency chat interactions.</p><p>Instead of juggling billing accounts, API keys, and rate limits for Anthropic, Google, and OpenAI, I just use OpenRouter. You write one OpenAI-compatible integration in your code, and you instantly get access to every major frontier model.</p><p>More importantly, it allows for seamless fallback routing. If Anthropic&#39;s API goes down on a Tuesday afternoon (which happens), my app automatically falls back to an equivalent OpenAI model. My users never see an error screen, and I don&#39;t have to write complex retry logic.</p><h2 id="use-copilot-instead-of-hyped-ai-ides" tabindex="-1">Use Copilot instead of hyped AI IDEs <a class="header-anchor" href="#use-copilot-instead-of-hyped-ai-ides" aria-label="Permalink to &quot;Use Copilot instead of hyped AI IDEs&quot;">​</a></h2><p>New, insanely expensive models are being released every week. I constantly hear about developers dropping hundreds of dollars a month on Cursor subscriptions and Anthropic API keys just to have an AI write their boilerplate.</p><p>Meanwhile, I&#39;m using Claude Opus 4.6 all day and my bill barely touches $60 a month. My secret? I exploit Microsoft&#39;s pricing model.</p><p>I bought a GitHub Copilot subscription in 2023, plugged it into standard VS Code, and never left. I tried Cursor and the other fancy forks when they briefly surpassed it with agentic coding, but Copilot Chat always catches up.</p><p>Here is the trick that you might have missed: somehow, Microsoft is able to charge per request, not per token. And a &quot;request&quot; is simply what I type into the chat box. Even if the agent spends the next 30 minutes chewing through my entire codebase, mapping dependencies, and changing hundreds of files, I still pay roughly $0.04.</p><p>The optimal strategy is simple: write brutally detailed prompts with strict success criteria (which is best practice anyway), tell the agent to &quot;keep going until all errors are fixed,&quot; hit enter, and go make a coffee while Satya Nadella subsidizes your compute costs.</p><h2 id="use-sqlite-for-everything" tabindex="-1">Use SQLite for everything <a class="header-anchor" href="#use-sqlite-for-everything" aria-label="Permalink to &quot;Use SQLite for everything&quot;">​</a></h2><p>I always start a new venture using <code>sqlite3</code> as the main database. Hear me out, this is not as insane as you think.</p><p>The enterprise mindset dictates that you need an out-of-process database server. But the truth is, a local SQLite file communicating over the C-interface or memory is orders of magnitude faster than making a TCP network hop to a remote Postgres server.</p><p>&quot;But what about concurrency?&quot; you ask. Many people think SQLite locks the whole database on every write. They are wrong. You just need to turn on Write-Ahead Logging (WAL). Execute this pragma once when you open the database:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PRAGMA journal_mode=WAL;</span></span>
<span class="line"><span>PRAGMA synchronous=NORMAL;</span></span></code></pre></div><p>Boom. Readers no longer block writers. Writers no longer block readers. You can now easily handle thousands of concurrent users off a single <code>.db</code> file on an NVMe drive.</p><p>Since implementing user authentication is usually the most annoying part of starting a new SQLite-based project, I built a library: <a href="https://github.com/smhanov/auth" target="_blank" rel="noreferrer">smhanov/auth</a>. It integrates directly with whatever database you are using and manages user signups, sessions, and password resets. It even lets users sign in with Google, Facebook, X, or their own company-specific SAML provider. No bloated dependencies, just simple, auditable code.</p><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>The tech industry wants you to believe that building a real business requires complex orchestration, massive monthly AWS bills, and millions in venture capital.</p><p>It doesn&#39;t.</p><p>By utilizing a single VPS, statically compiled binaries, local GPU hardware for batch AI tasks, and the raw speed of SQLite, you can bootstrap a highly scalable startup that costs less than the price of a few coffees a month. You add infinite runway to your project, giving yourself the time to actually solve your users&#39; problems instead of sweating your burn rate.</p><p>If you are interested in running lean, check out my auth library and agent implementations on my <a href="https://github.com/smhanov" target="_blank" rel="noreferrer">GitHub</a>. I’ll be hanging around the comments—let me know how you keep your server costs down, or tell me why I&#39;m completely wrong.</p>`,48)])])}const m=a(s,[["render",r]]);export{d as __pageData,m as default};
